q13 = 1.7+0.25*sqrt(mid_att+bass_att); //shp rad

trig = (bcount%32 == 0) && dbl_beat;
if (trig,
r1 = 4+int (rand(8));
r2 = max (2,int ((r1-2)*rand(1)));
r3 = -1*pow (2, int(rand(2)));

s1 = (1+int(rand(4)));
s2 = sqrt(rand(1.5))*s1;
if (rand(1)>0.5,s1=-s1,0);
s3 = -1*pow (2, int(rand(4)));

ndir = if (rand(1)<0.2,-1,1);
,0);

run = if (bvol_<0.4,0,if(bvol_>0.7,1,run));
slow = if (certain<1.7,1,if(certain>2.5,0,slow));

dir_ = dir_*dec_f+dir*(1-dec_f);
q4 = ndir;
movarg = (1+certain*2)*dt/4*dir_;
tmove += movarg;
q19=tmove;

//mask shift x
q20 = 1/r1;  //Anteil
q22 = q20*r2; //Limit
trelx += BPM/120/q20*run*dt* (1-0.5*slow) * r3 + ndir*movarg*run; //ungef. Bew. Korr
q21 = q20*int(trelx); //phase

//mask shift y
q25 = s1;  //Divisor, 1,2,3,4,6 bei 12 tubes
q26 = s2;  //Narrow
trely += BPM/120*1*q25*s3*run*dt* (1-0.5*slow);
q27 = int(trely)/q25;  //phase
//if (s2<1,q27 = trel1*s3,0); //besser aber nur bei grossem divisor und kleinem narrow

q10 = trel1;
q11 = max(0,certain-1)/2;

trig = (bcount%4==0) && dbl_beat;
tbers = max(0,if (bers, tbers+dt/2, tbers-dt/2));
vc = certain+bvol*0.25;
if (vc > 5.5+tbers, bers=1, if (vc < 4.5+tbers/5, bers=0;,0));

if (bers, if (trig,
if (rand(15)<1,dir *=-1,0);
ddx = int (rand(4)-2)/3;
ddy = - int (rand(3))/3, 0);,
if (trig, ddx=0; ddy=0;,0));

q17=ddx; q18 = ddy;
q16 = 1 ;
q6 = min(1,0.7/vc); //dimmt alle tubes
q7 = tlen;
q8 = 0.3 + 0.2*sin(tmove*0.07); //w lev
monitor = certain;

rot = 0.0; zoom = 1+movarg; warp = 0; dx = 0; dy = 0;

